#!/usr/bin/env bash
set -e
echo "→ locating Space Age OS dashboard…"
CSS=$(find /root /home /var/www /opt -maxdepth 7 -type f -name globals.css -path '*/src/app/*' 2>/dev/null | grep -vi node_modules | head -1)
if [ -z "$CSS" ]; then echo "✗ couldn't find src/app/globals.css — tell Claude"; exit 1; fi
PROJ=${CSS%/src/app/globals.css}
echo "→ project: $PROJ"
cd "$PROJ"
TS=$(date +%s)
cp src/app/globals.css "src/app/globals.css.bak.$TS"
cp src/app/layout.tsx  "src/app/layout.tsx.bak.$TS"
cp src/components/Sidebar.tsx "src/components/Sidebar.tsx.bak.$TS"
echo "→ writing liquid-glass globals.css"
echo "" | base64 -d > src/app/globals.css
echo "→ rebranding to Space Age OS"
sed -i 's/Agentic OS — Mission Control/Space Age OS — Mission Control/' src/app/layout.tsx
sed -i 's/Agentic <span/Space Age <span/' src/components/Sidebar.tsx
echo "→ building"
npm run build
echo "→ restarting"
pm2 restart all || (pkill -f "next start" ; nohup npm start >/tmp/spaceage.log 2>&1 &)
echo "✓ done — hard-refresh the dashboard (Ctrl+Shift+R)"
